proof_block:
// The synthetic ensures has implication form
//   H(pre, post1, post2) ==> det_set_equal(r1, r2, post1, post2)
// where `det_set_equal` is `(r1 == r2) && (post1 == post2)`.
// `r1`, `r2` are unit, so the load-bearing conjunct is full
// `Array<A,N>` structural equality, which decomposes field-wise into
//   (a) post1.seq === post2.seq      (Ghost<Seq<A>>)
//   (b) post1.ar  === post2.ar       ([A;N])
//
// (a) follows by Seq extensionality through the shared update target.
// (b) is the hard part: the only `=`-related fact on the `[A;N]` field
//     comes from `axiom_array_ext_equal`, i.e. pointwise equality.
//     We bridge via `lemma_array_index` (in `group_array_axioms`),
//     which connects the indexing operator to `array_view`, and the
//     inline `Array::view` that defines `self@ == self.seq@`.
//
// We wrap everything in `if H { ... }` so each inner assertion is
// recorded as `H ==> assertion` — exactly the shape the implication-
// form synthetic ensures consumes (the template that closed the
// PageAllocator family of `det_*` proofs).

broadcast use vstd::array::group_array_axioms;

if ({
    &&& (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post1_self_.wf())
    &&& (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post2_self_.wf())
}) {
    // (1) Seq-extensionality chain through the shared update target.
    lemma_array_set_det_seq_eq::<A, N>(
        pre_self_, i, out, post1_self_, post2_self_,
    );
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    assert(post1_self_.seq@ == post2_self_.seq@);
    assert(post1_self_.seq === post2_self_.seq);
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // (2) Pointwise equality of the `[A;N]` arrays through the seq view.
    //     The inline `Array::view()` definition gives
    //     `self@ == self.seq@`, and `lemma_array_index` (broadcast) gives
    //     `a[j] == array_view(a)[j]` for `0 <= j < N`.  Together with the
    //     seq equality from (1), the two `ar[j]` values coincide.
    assert forall|j: int| 0 <= j < N implies
        #[trigger] post1_self_.ar[j] == #[trigger] post2_self_.ar[j]
    by {
        assert(post1_self_.ar[j] == array_view(post1_self_.ar)[j]);
        assert(post2_self_.ar[j] == array_view(post2_self_.ar)[j]);
        assert(post1_self_@[j] == post2_self_@[j]);
    };

    // (3) Lift the pointwise `ar` equality to `=~=` and then to `==`.
    lemma_array_ar_eq_from_pointwise::<A, N>(post1_self_, post2_self_);
    assert(post1_self_.ar =~= post2_self_.ar);
    assert(post1_self_.ar == post2_self_.ar);
    assert(post1_self_.ar === post2_self_.ar);

    // (4) Combine the two field equalities into full struct equality.
    lemma_array_eq_from_fieldwise::<A, N>(post1_self_, post2_self_);
    assert(post1_self_ =~= post2_self_);
    assert(post1_self_ == post2_self_);

    // (5) Unit-typed return values are trivially equal.
    assert(r1 == r2);
    assert(r1 == ());
    assert(r2 == ());

    // (6) Final closure of the determinism predicate.
    assert(det_set_equal(r1, r2, post1_self_, post2_self_));
}

// Trivial outside the branch as well.
assert(r1 == r2);

helper_lemmas:
// Bridge from per-field equality to full struct equality on `Array<A, N>`.
// `Array<A, N>` has exactly two fields (`seq: Ghost<Seq<A>>` and `ar: [A;N]`),
// so structural equality decomposes field-wise — Verus discharges this
// lemma directly from its struct-equality axiom.
proof fn lemma_array_eq_from_fieldwise<A, const N: usize>(a1: Array<A, N>, a2: Array<A, N>)
    requires
        a1.seq === a2.seq,
        a1.ar === a2.ar,
    ensures
        a1 == a2,
{
}

// Drive the Seq-extensionality chain through the shared
// `pre.seq@.update(i as int, out)` target so both `=~=` ensures fire
// against the same RHS and the resulting `==` lifts to the
// `Ghost<Seq<A>>` field-level equality.
proof fn lemma_array_set_det_seq_eq<A, const N: usize>(
    pre_self_: Array<A, N>,
    i: usize,
    out: A,
    post1: Array<A, N>,
    post2: Array<A, N>,
)
    requires
        0 <= i < N,
        pre_self_.wf(),
        post1.seq@ =~= pre_self_.seq@.update(i as int, out),
        post1.wf(),
        post2.seq@ =~= pre_self_.seq@.update(i as int, out),
        post2.wf(),
    ensures
        post1.seq@ =~= post2.seq@,
        post1.seq@ == post2.seq@,
        post1.seq === post2.seq,
        post1@ =~= post2@,
        post1@ == post2@,
{
    assert(post1.seq@ =~= pre_self_.seq@.update(i as int, out));
    assert(post2.seq@ =~= pre_self_.seq@.update(i as int, out));
    assert(post1.seq@ =~= post2.seq@);
    assert(post1.seq@ == post2.seq@);
    assert(post1.seq === post2.seq);
}

// Lift `[A;N]` pointwise equality to full `=~=` (and hence `==`) on the
// `ar` field via `axiom_array_ext_equal`.
proof fn lemma_array_ar_eq_from_pointwise<A, const N: usize>(a1: Array<A, N>, a2: Array<A, N>)
    requires
        forall|i: int| 0 <= i < N ==> #[trigger] a1.ar[i] == #[trigger] a2.ar[i],
    ensures
        a1.ar =~= a2.ar,
        a1.ar == a2.ar,
        a1.ar === a2.ar,
{
    broadcast use vstd::array::group_array_axioms;
    assert(a1.ar =~= a2.ar);
}
